#include <bits/stdc++.h>using namespace std; #define ll long long int main() {    ios::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin >> t;    while (t--) {        int n;        cin>>n;        int temp;        unordered_map<int,int>Map;        for(int i=0;i<n;i++){            for(int j=0;j<n;j++){                cin>>temp;                Map[temp]++;            }        }        bool ans=true;        for(auto i : Map){            if(i.second>((n*n)-n)){                ans=false;                break;            }        }        if(ans){            cout<<"YES"<<"\n";        }        else cout<<"NO"<<"\n";    }     return 0;}